const body = $input.first().json.body || {};
const topic = body.topic || 'technology';
const channelId = body.channel_id || '';
const responseUrl = body.response_url || '';

return [{ json: {
  topic,
  channelId,
  responseUrl
}}];

// Parse RSS XML into articles array
const xmlText = $input.first().json.data || $input.first().json.body || '';
const items = [];
const itemRegex = /<item>([\s\S]*?)<\/item>/g;
let match;

while ((match = itemRegex.exec(xmlText)) !== null && items.length < 5) {
  const item = match[1];
  const getTag = (tag) => {
    const m = item.match(new RegExp(`<${tag}[^>]*>(?:<![CDATA[)?([\ s\S]*?)(?:\]\]>)?<\/${tag}>`, 'i'));
    return m ? m[1].trim() : '';
  };

  const title = getTag('title').replace(/<[^>]+>/g, '');
  const source = getTag('source') || getTag('dc:creator') || 'Unknown';
  const date = getTag('pubDate') || getTag('dc:date') || '';
  const description = getTag('description').replace(/<[^>]+>/g, '').slice(0, 200);
  const url = getTag('link') || getTag('guid');

  if (title && url) {
    items.push({
      title,
      source,
      date,
      description,
      url
    });
  }
}

const topic = $('Parse Request').first().json.topic;
return [{ json: { topic, articles: items } }];

// Parse Ollama response and format Slack blocks
const ollamaResp = $input.first().json;
const msgContent = ollamaResp.message?.content || '{}';
let articlesData = [];

try {
  // Try to extract JSON from the response
  const jsonMatch = msgContent.match(/\[\s*\{[\s\S]*?\}\s*\]/); 
  articlesData = jsonMatch ? JSON.parse(jsonMatch[0]) : $('Parse RSS').first().json.articles;
} catch (e) {
  articlesData = $('Parse RSS').first().json.articles;
}

const topic = $('Parse RSS').first().json.topic;

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: ':newspaper: Top 5 News Results: ' + topic, emoji: true }
  },
  { type: 'divider' }
];

articlesData.forEach((article, idx) => {
  blocks.push({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*<${article.url}|${article.title}>*\n${article.source} • ${article.date}\n_${article.summary || article.description}_`
    }
  });

  if (idx < articlesData.length - 1) {
    blocks.push({ type: 'divider' });
  }
});

const responseUrl = $('Parse Request').first().json.responseUrl;
return [{ json: {
  responseUrl,
  blocks
}}];
